const PROJECT = 'cosmetic-formulator';
const TITLE = 'Cosmetic Formulator';
const WEBHOOK = 'https://YOUR_N8N_INSTANCE.app.n8n.cloud/webhook/cosmetic-formulator';
const LOG_URL = 'https://YOUR_N8N_INSTANCE.app.n8n.cloud/webhook/log-interaction';
const FB_URL = 'https://YOUR_N8N_INSTANCE.app.n8n.cloud/webhook/log-feedback';
const AUTH = 'YOUR_AUTH_TOKEN';
const PLACEHOLDER = 'Ask about formulas...';

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
<title>${TITLE}</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #0f0f0f; color: #e0e0e0; height: 100dvh; display: flex; flex-direction: column; }
  header { padding: 12px 16px; background: #1a1a2e; border-bottom: 1px solid #333; text-align: center; font-size: 18px; font-weight: 600; }
  #chat { flex: 1; overflow-y: auto; padding: 12px 16px; display: flex; flex-direction: column; gap: 10px; }
  .msg { max-width: 85%; padding: 10px 14px; border-radius: 16px; line-height: 1.45; font-size: 15px; white-space: pre-wrap; word-wrap: break-word; }
  .user { align-self: flex-end; background: #2563eb; color: #fff; border-bottom-right-radius: 4px; }
  .bot { align-self: flex-start; background: #2a2a2a; border-bottom-left-radius: 4px; }
  .typing { align-self: flex-start; background: #2a2a2a; border-radius: 16px; padding: 10px 18px; font-size: 15px; color: #888; }
  .fb-row { align-self: flex-start; display: flex; gap: 6px; margin-top: -4px; }
  .fb-btn { background: none; border: 1px solid #444; border-radius: 12px; padding: 4px 10px; color: #888; font-size: 13px; cursor: pointer; }
  .fb-btn:hover { border-color: #2563eb; color: #ccc; }
  .fb-btn.selected { border-color: #2563eb; color: #2563eb; }
  .fb-input { display: none; align-self: flex-start; width: 85%; max-width: 85%; margin-top: -4px; }
  .fb-input input { width: 100%; padding: 8px 12px; border-radius: 12px; border: 1px solid #444; background: #1a1a1a; color: #fff; font-size: 14px; outline: none; }
  .fb-input input:focus { border-color: #2563eb; }
  .trace-box { align-self: flex-start; max-width: 85%; margin-top: -4px; }
  .trace-box summary { color: #666; font-size: 12px; cursor: pointer; padding: 4px 0; }
  .trace-box summary:hover { color: #2563eb; }
  .trace-text { background: #1a1a1a; border: 1px solid #333; border-radius: 8px; padding: 8px 12px; margin-top: 4px; font-family: monospace; font-size: 12px; color: #aaa; white-space: pre-wrap; word-wrap: break-word; max-height: 300px; overflow-y: auto; }
  form { display: flex; gap: 8px; padding: 10px 12px; background: #1a1a1a; border-top: 1px solid #333; }
  input { flex: 1; padding: 12px 14px; border-radius: 24px; border: 1px solid #444; background: #222; color: #fff; font-size: 16px; outline: none; }
  input:focus { border-color: #2563eb; }
  button { padding: 12px 20px; border-radius: 24px; border: none; background: #2563eb; color: #fff; font-size: 16px; font-weight: 600; cursor: pointer; }
  button:disabled { opacity: 0.5; }
</style>
</head>
<body>
<header>${TITLE}</header>
<div id="chat"></div>
<form id="form">
  <input id="input" type="text" placeholder="${PLACEHOLDER}" autocomplete="off" />
  <button id="btn" type="submit">Send</button>
</form>
<script>
const PROJECT = '${PROJECT}';
const WEBHOOK = '${WEBHOOK}';
const LOG_URL = '${LOG_URL}';
const FB_URL = '${FB_URL}';
const AUTH = '${AUTH}';
const chat = document.getElementById('chat');
const form = document.getElementById('form');
const inp = document.getElementById('input');
const btn = document.getElementById('btn');

function addMsg(text, cls) {
  const d = document.createElement('div');
  d.className = 'msg ' + cls;
  d.textContent = text;
  chat.appendChild(d);
  chat.scrollTop = chat.scrollHeight;
  return d;
}

function addFeedback(interactionId, userMsg, aiResp) {
  const row = document.createElement('div');
  row.className = 'fb-row';
  const up = document.createElement('button');
  up.className = 'fb-btn'; up.textContent = '\u{1F44D}';
  const down = document.createElement('button');
  down.className = 'fb-btn'; down.textContent = '\u{1F44E}';
  const edit = document.createElement('button');
  edit.className = 'fb-btn'; edit.textContent = '\u270F Correct';
  row.appendChild(up); row.appendChild(down); row.appendChild(edit);
  chat.appendChild(row);

  const corrBox = document.createElement('div');
  corrBox.className = 'fb-input';
  const corrInp = document.createElement('input');
  corrInp.placeholder = 'What should it have said?';
  corrBox.appendChild(corrInp);
  chat.appendChild(corrBox);
  chat.scrollTop = chat.scrollHeight;

  function sendFb(rating, correction) {
    fetch(FB_URL, { method:'POST', headers:{'Content-Type':'application/json', 'X-Auth-Token': AUTH},
      body: JSON.stringify({ interaction_id: interactionId, project: PROJECT, rating, correction, category:'auto' })
    }).catch(()=>{});
    up.classList.remove('selected'); down.classList.remove('selected');
    if (rating >= 4) up.classList.add('selected');
    else down.classList.add('selected');
    up.disabled = true; down.disabled = true; edit.disabled = true;
    corrBox.style.display = 'none';
  }

  up.onclick = () => sendFb(5, '');
  down.onclick = () => { corrBox.style.display = 'block'; corrInp.focus(); chat.scrollTop = chat.scrollHeight; };
  edit.onclick = () => { corrBox.style.display = 'block'; corrInp.focus(); chat.scrollTop = chat.scrollHeight; };
  corrInp.addEventListener('keydown', (e) => {
    if (e.key === 'Enter' && corrInp.value.trim()) {
      sendFb(down.classList.contains('selected') ? 1 : 3, corrInp.value.trim());
    }
  });
}

function addTrace(trace) {
  const details = document.createElement("details");
  details.className = "trace-box";
  const summary = document.createElement("summary");
  summary.textContent = "Show reasoning";
  details.appendChild(summary);
  const pre = document.createElement("pre");
  pre.className = "trace-text";
  pre.textContent = trace;
  details.appendChild(pre);
  chat.appendChild(details);
  chat.scrollTop = chat.scrollHeight;
}

form.addEventListener('submit', async (e) => {
  e.preventDefault();
  const msg = inp.value.trim();
  if (!msg) return;
  addMsg(msg, 'user');
  inp.value = '';
  btn.disabled = true;
  const dot = document.createElement('div');
  dot.className = 'typing'; dot.textContent = 'Thinking...';
  chat.appendChild(dot); chat.scrollTop = chat.scrollHeight;
  const t0 = Date.now();
  try {
    const res = await fetch(WEBHOOK, { method:'POST', headers:{'Content-Type':'application/json', 'X-Auth-Token': AUTH}, body: JSON.stringify({ message: msg }) });
    const raw = await res.text();
    const elapsed = Date.now() - t0;
    let text = raw, trace = '', toolsUsed = '';
    try { const d = JSON.parse(raw); text = d.output || raw; trace = d.decisionTrace || ''; toolsUsed = d.toolsUsed || ''; } catch(e) {}
    dot.remove();
    addMsg(text, 'bot');
    if (trace && trace \!== 'No tools were called for this response.') { addTrace(trace); }
    const iid = Date.now().toString();
    addFeedback(iid, msg, text);
    fetch(LOG_URL, { method:'POST', headers:{'Content-Type':'application/json', 'X-Auth-Token': AUTH},
      body: JSON.stringify({ interaction_id: iid, project: PROJECT, user_message: msg, ai_response: text, tools_used: toolsUsed, decision_trace: trace, response_time: elapsed })
    }).catch(()=>{});
  } catch (err) {
    dot.remove();
    addMsg('Error: ' + err.message, 'bot');
  }
  btn.disabled = false;
  inp.focus();
});
</script>
</body>
</html>`;

return [{ json: { html } }];
